mapper.select:
SELECT eu.id AS equipment_unit_id, eu.display_code
FROM equipment_units eu
WHERE eu.product_id = #{productId}
  AND eu.id = #{equipmentUnitId}
  AND eu.status = 'AVAILABLE'
FOR UPDATE

SELECT r.id
FROM inventory_reservations r
WHERE r.equipment_unit_id = #{equipmentUnitId}
  AND r.status = 'ACTIVE'
  AND r.expires_at > CURRENT_TIMESTAMP(6)
  AND r.start_at < #{endAt}
  AND r.end_at > #{startAt}
ORDER BY r.id ASC
LIMIT 1
FOR UPDATE

SELECT o.id
FROM rental_orders o
WHERE o.equipment_unit_id = #{equipmentUnitId}
  AND o.status = 'CONFIRMED'
  AND o.start_at < #{endAt}
  AND o.end_at > #{startAt}
ORDER BY o.id ASC
LIMIT 1
FOR UPDATE
